static int decode_frame ( AVCodecContext * avctx , void * data , int * got_frame , AVPacket * avpkt ) {
 KmvcContext * const ctx = avctx -> priv_data ;
 uint8_t * out , * src ;
 int i , ret ;
 int header ;
 int blocksize ;
 const uint8_t * pal = av_packet_get_side_data ( avpkt , AV_PKT_DATA_PALETTE , NULL ) ;
 bytestream2_init ( & ctx -> g , avpkt -> data , avpkt -> size ) ;
 if ( ctx -> pic . data [ 0 ] ) avctx -> release_buffer ( avctx , & ctx -> pic ) ;
 ctx -> pic . reference = 1 ;
 ctx -> pic . buffer_hints = FF_BUFFER_HINTS_VALID ;
 if ( ( ret = ff_get_buffer ( avctx , & ctx -> pic ) ) < 0 ) {
 av_log ( avctx , AV_LOG_ERROR , "get_buffer() failed\n" ) ;
 return ret ;
 }
 header = bytestream2_get_byte ( & ctx -> g ) ;
 if ( bytestream2_peek_byte ( & ctx -> g ) == 127 ) {
 bytestream2_skip ( & ctx -> g , 3 ) ;
 for ( i = 0 ;
 i < 127 ;
 i ++ ) {
 ctx -> pal [ i + ( header & 0x81 ) ] = bytestream2_get_be24 ( & ctx -> g ) ;
 bytestream2_skip ( & ctx -> g , 1 ) ;
 }
 bytestream2_seek ( & ctx -> g , - 127 * 4 - 3 , SEEK_CUR ) ;
 }
 if ( header & KMVC_KEYFRAME ) {
 ctx -> pic . key_frame = 1 ;
 ctx -> pic . pict_type = AV_PICTURE_TYPE_I ;
 }
 else {
 ctx -> pic . key_frame = 0 ;
 ctx -> pic . pict_type = AV_PICTURE_TYPE_P ;
 }
 if ( header & KMVC_PALETTE ) {
 ctx -> pic . palette_has_changed = 1 ;
 for ( i = 1 ;
 i <= ctx -> palsize ;
 i ++ ) {
 ctx -> pal [ i ] = bytestream2_get_be24 ( & ctx -> g ) ;
 }
 }
 if ( pal ) {
 ctx -> pic . palette_has_changed = 1 ;
 memcpy ( ctx -> pal , pal , AVPALETTE_SIZE ) ;
 }
 if ( ctx -> setpal ) {
 ctx -> setpal = 0 ;
 ctx -> pic . palette_has_changed = 1 ;
 }
 memcpy ( ctx -> pic . data [ 1 ] , ctx -> pal , 1024 ) ;
 blocksize = bytestream2_get_byte ( & ctx -> g ) ;
 if ( blocksize != 8 && blocksize != 127 ) {
 av_log ( avctx , AV_LOG_ERROR , "Block size = %i\n" , blocksize ) ;
 return AVERROR_INVALIDDATA ;
 }
 memset ( ctx -> cur , 0 , 320 * 200 ) ;
 switch ( header & KMVC_METHOD ) {
 case 0 : case 1 : memcpy ( ctx -> cur , ctx -> prev , 320 * 200 ) ;
 break ;
 case 3 : kmvc_decode_intra_8x8 ( ctx , avctx -> width , avctx -> height ) ;
 break ;
 case 4 : kmvc_decode_inter_8x8 ( ctx , avctx -> width , avctx -> height ) ;
 break ;
 default : av_log ( avctx , AV_LOG_ERROR , "Unknown compression method %i\n" , header & KMVC_METHOD ) ;
 return AVERROR_INVALIDDATA ;
 }
 out = ctx -> pic . data [ 0 ] ;
 src = ctx -> cur ;
 for ( i = 0 ;
 i < avctx -> height ;
 i ++ ) {
 memcpy ( out , src , avctx -> width ) ;
 src += 320 ;
 out += ctx -> pic . linesize [ 0 ] ;
 }
 if ( ctx -> cur == ctx -> frm0 ) {
 ctx -> cur = ctx -> frm1 ;
 ctx -> prev = ctx -> frm0 ;
 }
 else {
 ctx -> cur = ctx -> frm0 ;
 ctx -> prev = ctx -> frm1 ;
 }
 * got_frame = 1 ;
 * ( AVFrame * ) data = ctx -> pic ;
 return avpkt -> size ;
 }

static char * fstrndup ( const char * ptr , unsigned long len ) {
 char * result ;
 if ( len <= 0 ) return NULL ;
 result = ALLOC_N ( char , len ) ;
 memccpy ( result , ptr , 0 , len ) ;
 return result ;
 }

static int do_uncompress ( compress_filter_context_t * zfx , z_stream * zs , IOBUF a , size_t * ret_len ) {
 int zrc ;
 int rc = 0 ;
 size_t n ;
 int nread , count ;
 int refill = ! zs -> avail_in ;
 if ( DBG_FILTER ) log_debug ( "begin inflate: avail_in=%u, avail_out=%u, inbuf=%u\n" , ( unsigned ) zs -> avail_in , ( unsigned ) zs -> avail_out , ( unsigned ) zfx -> inbufsize ) ;
 do {
 if ( zs -> avail_in < zfx -> inbufsize && refill ) {
 n = zs -> avail_in ;
 if ( ! n ) # ifndef __riscos__ zs -> next_in = zfx -> inbuf ;
 # else zs -> next_in = ( Bytef * ) zfx -> inbuf ;
 # endif count = zfx -> inbufsize - n ;
 nread = iobuf_read ( a , zfx -> inbuf + n , count ) ;
 if ( nread == - 1 ) nread = 0 ;
 n += nread ;
 if ( nread < count && zfx -> algo == 1 ) {
 * ( zfx -> inbuf + n ) = 0xFF ;
 zfx -> algo1hack = 1 ;
 n ++ ;
 }
 zs -> avail_in = n ;
 }
 refill = 1 ;
 if ( DBG_FILTER ) log_debug ( "enter inflate: avail_in=%u, avail_out=%u\n" , ( unsigned ) zs -> avail_in , ( unsigned ) zs -> avail_out ) ;
 # ifdef Z_SYNC_FLUSH zrc = inflate ( zs , Z_SYNC_FLUSH ) ;
 # else zrc = inflate ( zs , Z_PARTIAL_FLUSH ) ;
 # endif if ( DBG_FILTER ) log_debug ( "leave inflate: avail_in=%u, avail_out=%u, zrc=%d\n" , ( unsigned ) zs -> avail_in , ( unsigned ) zs -> avail_out , zrc ) ;
 if ( zrc == Z_STREAM_END ) rc = - 1 ;
 else if ( zrc != Z_OK && zrc != Z_BUF_ERROR ) {
 if ( zs -> msg ) log_fatal ( "zlib inflate problem: %s\n" , zs -> msg ) ;
 else log_fatal ( "zlib inflate problem: rc=%d\n" , zrc ) ;
 }
 }
 while ( zs -> avail_out && zrc != Z_STREAM_END && zrc != Z_BUF_ERROR ) ;
 * ret_len = zfx -> outbufsize - zs -> avail_out ;
 if ( DBG_FILTER ) log_debug ( "do_uncompress: returning %u bytes\n" , ( unsigned ) * ret_len ) ;
 return rc ;
 }

