 key [ 2 ] . length = 1 ;
 key [ 2 ] . key = & device_address ;
 key [ 3 ] . length = 0 ;
 key [ 3 ] . key = NULL ;
 }
 else {
 key [ 0 ] . length = 1 ;
 key [ 0 ] . key = & interface_id ;
 key [ 1 ] . length = 1 ;
 key [ 2 ] . length = 1 ;
 if ( direction == P2P_DIR_SENT ) {
 key [ 1 ] . key = & pinfo -> srcport ;
 key [ 2 ] . key = & pinfo -> destport ;
 }
